def timer(func):
    def wrapper(*args, **kwargs):
        import time
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"Took {end-start:.4f}s")
        return result
    return wrapper

@timer
def slow_add(a, b):
    import time
    time.sleep(0.5)
    return a + b

print(slow_add(3, 5))
